    def removeDuplicates(self, head: ListNode) -> ListNode:
        if not head or not head.next:
            return head

        dummy = head

        while head and head.next:
            if head.val == head.next.val:
                prev = head

                while head and head.next and head.val == head.next.val:
                    head = head.next

                prev.next = head

            else:
                prev = head

                head = head.next


        return dummy




