// Template code to read input from readline and print output to process.stdout

import readline from 'readline';
import { stdin, stdout } from 'process';

const rl = readline.createInterface({
    input: stdin,
    output: stdout
});

let input = '';

rl.on('line', line => {
    input += line + '\n';
});

rl.on('close', () => {
    const lines = input.trim().split('\n');
    const n = parseInt(lines[0]);

    // Create the linked list 1 -> 2 -> 2 -> 3 -> 4 -> 4 -> 5
    let current = null;
    let head = null;
    for (let i = 0; i < n; i++) {
        const val = parseInt(lines[i + 1]);
        const node = new ListNode(val);
        if (head === null) {
            head = node;
            current = node;
        } else {
            current.next = node;
            current = node;
        }
    }

    // Remove duplicates
    function removeDuplicates(head) {
        if (head === null || head.next === null) {
            return head;
        }

        let current = head;

        while (current.next) {
            if (current.val !== current.next.val) {
                current = current.next;
            }
        }

        return head;
    }

    const solution = new Solution();
    const newHead = solution.removeDuplicates(head);

    // Print the updated linked list
    let result = '';
    let current = newHead;
    while (current) {
        result += current.val + ' -> ';
        current = current.next;
    }
    process.stdout.write('Before removing duplicates:\n' + result + ' NULL\n\n');

    result = '';
    current = newHead;
    while (current) {
        result += current.val + ' -> ';
        current = current.next;
    }
    process.stdout.write('After removing duplicates:\n' + result + ' NULL\n');

    return 0;
});
